+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  const image = text[start] === '!';
+  const labelStart = start + (image ? 1 : 0);
+  if (text[labelStart] !== '[') {
+    return null;
+  }
+
+  const labelEnd = findClosingBracket(text, labelStart);
+  if (labelEnd === -1 || text[labelEnd + 1] !== '(') {
+    return null;
+  }
+
+  const destinationEnd = findClosingParenthesis(text, labelEnd + 1);
+  if (destinationEnd === -1) {
+    return null;
+  }
+
+  const label = text.substring(labelStart + 1, labelEnd);
+  const destination = text.substring(labelEnd + 2, destinationEnd);
+  if (label.includes('\
