+function findClosingParenthesis(text: string, start: number): number {
+  let depth = 0;
+  let inAngleBrackets = false;
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === '<') {
+      inAngleBrackets = true;
+    } else if (text[index] === '>' && inAngleBrackets) {
+      inAngleBrackets = false;
+    } else if (!inAngleBrackets && text[index] === '(') {
+      depth++;
+    } else if (!inAngleBrackets && text[index] === ')' && --depth === 0) {
+      return index;
+    }
+  }
+  return -1;
