+  const trimmed = destination.trim();
+  if (!trimmed) {
+    return '';
+  }
+
+  if (trimmed[0] === '<') {
+    const closing = findUnescapedCharacter(trimmed, '>', 1);
+    if (closing === -1 || trimmed.substring(closing + 1).trim() !== '') {
+      return null;
+    }
+    return trimmed.substring(1, closing);
+  }
+
+  let depth = 0;
+  for (let index = 0; index < trimmed.length; index++) {
+    if (trimmed[index] === '\\\') {
+      index++;
+    } else if (trimmed[index] === '(') {
+      depth++;
+    } else if (trimmed[index] === ')') {
+      depth--;
+    } else if (/\\s/.test(trimmed[index]) && depth === 0) {
+      return trimmed.substring(index).trim() === '' ? trimmed.substring(0, index) : null;
+    }
+  }
+  return trimmed;
